r.x:
var $bm_rt;
var fps, this_point, that_point, delta, angle;
fps = 25;
this_point = thisLayer.position.valueAtTime($bm_sub(time, $bm_div(0.01, fps)));
that_point = thisLayer.position;
delta = sub(this_point, that_point);
angle = Math.atan2(delta[1], delta[0]);
$bm_rt = $bm_sum(radiansToDegrees(angle), value);

p.x:
var $bm_rt;
var tPath, tLastFrame, tFirstFrame, tPercentage, tPercentageAsATime, myPos;
tPath = thisLayer.transform.position;
tLastFrame = tPath.key(tPath.numKeys).time;
tFirstFrame = tPath.key(1).time;
tPercentage = $bm_div(parent.content('Shape 1').content('Trim Paths 1').start, 100);
tPercentageAsATime = $bm_sum($bm_mul(tPercentage, $bm_sub(tLastFrame, tFirstFrame)), tFirstFrame);
$bm_rt = myPos = tPath.valueAtTime(tPercentageAsATime);

s.x:
